mapper.select:
select id, platform_code, platform_name, platform_logistics_code, platform_logistics_name, template_id, template_type, template_name,
template_url, preview_url, brand_code, template_ext_info, auto_get_flag, type, state, remark, created_by, created_name, created_date,
modified_by, modified_name, modified_date, version, deleted_flag
from base_platform_print_template pt
where pt.deleted_flag = 0

    and pt.platform_code = #{platformCode}


    and pt.platform_logistics_code = #{platformLogisticsCode,jdbcType=VARCHAR}


    and pt.template_id = #{templateId}


    and pt.template_type = #{templateId}


    and pt.type = #{type}
